export const runtime = "nodejs";

import { NextResponse } from "next/server";
import { poolInstance as pool } from "@/lib/db";
import fs from "fs";

export async function GET(req: Request) {
  const url = new URL(req.url);
  const date = url.searchParams.get("date"); // YYYY-MM-DD
  if (!date) return NextResponse.json({ ok: false, error: "Falta date" }, { status: 400 });

  const client = await pool.connect();
  try {
    const r = await client.query(
      `SELECT file_name, file_path FROM public.reportes_diarios WHERE report_date = $1::date`,
      [date]
    );

    if (r.rows.length === 0) {
      return NextResponse.json({ ok: false, error: "No existe reporte para esa fecha" }, { status: 404 });
    }

    const { file_name, file_path } = r.rows[0];

    if (!fs.existsSync(file_path)) {
      return NextResponse.json({ ok: false, error: "Archivo no encontrado en servidor" }, { status: 404 });
    }

    const buf = fs.readFileSync(file_path);

    return new NextResponse(buf, {
      status: 200,
      headers: {
        "Content-Type": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        "Content-Disposition": `attachment; filename="${file_name}"`,
      },
    });
  } finally {
    client.release();
  }
}
